import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.math.BigDecimal;
import java.util.*;
import java.util.stream.*;

class Product {
    private Long id;
    private String name;
    private String category;
    private BigDecimal price;
    private boolean inStock;

    public Product(Long id, String name, String category, BigDecimal price, boolean inStock) {
        this.id = id; this.name = name; this.category = category;
        this.price = price; this.inStock = inStock;
    }
    public Long getId() { return id; }
    public String getName() { return name; }
    public String getCategory() { return category; }
    public BigDecimal getPrice() { return price; }
    public boolean isInStock() { return inStock; }
}

class PagedResponse<T> {
    private List<T> content;
    private int page;
    private int size;
    private long totalElements;
    private int totalPages;

    public PagedResponse(List<T> content, int page, int size, long totalElements) {
        this.content = content; this.page = page; this.size = size;
        this.totalElements = totalElements;
        this.totalPages = (int) Math.ceil((double) totalElements / size);
    }
    public List<T> getContent() { return content; }
    public int getPage() { return page; }
    public int getSize() { return size; }
    public long getTotalElements() { return totalElements; }
    public int getTotalPages() { return totalPages; }
}

@RestController
@RequestMapping("/api/v1/products")
public class ProductController {

    private List<Product> products = Arrays.asList(
        new Product(1L, "Laptop Pro", "Electronics", new BigDecimal("1299.99"), true),
        new Product(2L, "Wireless Mouse", "Electronics", new BigDecimal("29.99"), true),
        new Product(3L, "Office Chair", "Furniture", new BigDecimal("399.99"), false),
        new Product(4L, "Standing Desk", "Furniture", new BigDecimal("799.99"), true),
        new Product(5L, "USB-C Hub", "Electronics", new BigDecimal("49.99"), true)
    );

    @GetMapping
    public ResponseEntity<PagedResponse<Product>> getProducts(
            @RequestParam(required = false) String category,
            @RequestParam(required = false) Boolean inStock,
            @RequestParam(defaultValue = "0") int page,
            @RequestParam(defaultValue = "10") int size,
            @RequestParam(defaultValue = "name") String sortBy) {

        // Filtering
        List<Product> filtered = products.stream()
            .filter(p -> category == null || p.getCategory().equalsIgnoreCase(category))
            .filter(p -> inStock == null || p.isInStock() == inStock)
            .sorted(Comparator.comparing(p -> {
                if ("price".equals(sortBy)) return p.getPrice().toPlainString();
                return p.getName();
            }))
            .collect(Collectors.toList());

        // Pagination
        int start = page * size;
        int end = Math.min(start + size, filtered.size());
        List<Product> pageContent = start >= filtered.size() ?
            Collections.emptyList() : filtered.subList(start, end);

        return ResponseEntity.ok(new PagedResponse<>(pageContent, page, size, filtered.size()));
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable Long id) {
        return products.stream()
            .filter(p -> p.getId().equals(id))
            .findFirst()
            .map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }
}

