import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import java.net.URI;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@RestController
@RequestMapping("/api")
public class UrlShortenerController {

    private Map<String, String> urlStore = new ConcurrentHashMap<>();
    private static final String CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";
    private Random random = new Random();

    private String generateCode() {
        StringBuilder sb = new StringBuilder(6);
        for (int i = 0; i < 6; i++) {
            sb.append(CHARS.charAt(random.nextInt(CHARS.length())));
        }
        return sb.toString();
    }

    @PostMapping("/shorten")
    public ResponseEntity<Map<String, String>> shorten(@RequestBody Map<String, String> request) {
        String url = request.get("url");
        if (url == null || !url.startsWith("http")) {
            return ResponseEntity.badRequest().body(Map.of("error", "Invalid URL"));
        }
        String code;
        do { code = generateCode(); } while (urlStore.containsKey(code));
        urlStore.put(code, url);
        String shortUrl = "http://localhost:8080/api/" + code;
        Map<String, String> response = new LinkedHashMap<>();
        response.put("shortCode", code);
        response.put("shortUrl", shortUrl);
        response.put("originalUrl", url);
        return ResponseEntity.status(HttpStatus.CREATED).body(response);
    }

    @GetMapping("/{shortCode}")
    public ResponseEntity<Void> redirect(@PathVariable String shortCode) {
        String originalUrl = urlStore.get(shortCode);
        if (originalUrl == null) {
            return ResponseEntity.notFound().build();
        }
        return ResponseEntity.status(HttpStatus.FOUND)
            .location(URI.create(originalUrl)).build();
    }
}

import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import java.util.*;

class Student {
    Long id; String name; String studentId;
    List<Grade> grades = new ArrayList<>();
    public Student(Long id, String name, String studentId) {
        this.id = id; this.name = name; this.studentId = studentId;
    }
}

class Grade {
    String subject; int score; String letterGrade;
    public Grade(String subject, int score) {
        this.subject = subject; this.score = score;
        if (score >= 90) letterGrade = "A";
        else if (score >= 80) letterGrade = "B+";
        else if (score >= 70) letterGrade = "C";
        else if (score >= 60) letterGrade = "D";
        else letterGrade = "F";
    }
}

@RestController
@RequestMapping("/api/students")
public class GradeBookController {
    private Map<Long, Student> students = new HashMap<>();
    private long idCounter = 1;

    @PostMapping
    public ResponseEntity<Student> createStudent(@RequestBody Map<String, String> body) {
        Student s = new Student(idCounter++, body.get("name"), body.get("studentId"));
        students.put(s.id, s);
        return ResponseEntity.status(201).body(s);
    }

    @PostMapping("/{id}/grades")
    public ResponseEntity<?> addGrade(@PathVariable Long id, @RequestBody Map<String, Object> body) {
        Student s = students.get(id);
        if (s == null) return ResponseEntity.notFound().build();
        int score = (Integer) body.get("score");
        if (score < 0 || score > 100) return ResponseEntity.badRequest().body("Score must be 0-100");
        s.grades.add(new Grade((String) body.get("subject"), score));
        return ResponseEntity.status(201).body(s);
    }

    @GetMapping("/{id}/report")
    public ResponseEntity<?> getReport(@PathVariable Long id) {
        Student s = students.get(id);
        if (s == null) return ResponseEntity.notFound().build();
        double avg = s.grades.stream().mapToInt(g -> g.score).average().orElse(0);
        Map<String, Object> report = new LinkedHashMap<>();
        report.put("id", s.id); report.put("name", s.name);
        report.put("studentId", s.studentId); report.put("grades", s.grades);
        report.put("averageScore", avg);
        report.put("gpa", avg >= 90 ? 4.0 : avg >= 80 ? 3.5 : avg >= 70 ? 3.0 : 2.0);
        return ResponseEntity.ok(report);
    }
}
